refentry.refsect1:
&reftitle.description;
public boolYaf_View_Simple::assignRef stringname mixedvalue
Anders als Yaf_View_Simple::assign weist diese Methode der Engine einen Referenzwert zu.

  &reftitle.examples;

   Beispiel für Yaf_View_Simple::assignRef


<?php
class IndexController extends Yaf_Controller_Abstract {
    public function indexAction() {
        $value = "bar";
        $this->getView()->assign("foo", $value);

        /* bitte beachten, dass es vor Yaf 2.1.4 einen Fehler gab,
         * durch den die folgende Ausgabe "bar" lautet;
         */
        $dummy = $this->getView()->render("index/index.phtml");
        echo $value;

        // verhindert das automatische Rendern
        Yaf_Dispatcher::getInstance()->autoRender(FALSE);
    }
}
?>




   Beispiel für ein Template


<html>
 <head>
  <title><?php echo $foo;  $foo = "changed"; ?></title>
 </head>
<body>
</body>
</html>


   &example.outputs.similar;


